mapper.select:
SELECT cat_no, cat_code, cat_name, cat_type, seqno, visible
FROM category
WHERE cat_no = #{cat_no}

SELECT cat_no, cat_code, cat_name, cat_type, seqno, visible, r FROM ( SELECT cat_no, cat_code, cat_name, cat_type, seqno, visible, rownum as r FROM ( SELECT cat_no, cat_code, cat_name, cat_type, seqno, visible FROM category
WHERE UPPER(cat_name) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(cat_type) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(cat_code) LIKE '%' || UPPER(#{word}) || '%'
ORDER BY seqno ASC ) ) WHERE r >= #{start_num} AND r <= #{end_num}
